/* === 环形缓冲区数据结构 === */
typedef struct {
    uint8_t  buf[BUFFER_SIZE];     /* 256 字节缓冲区 */
    volatile uint16_t head;        /* DMA 写入位置 */
    volatile uint16_t tail;        /* 应用层读取位置 */
} dma_ring_buf_t;

/* 静态实例 —— 放在 DTCM 或 SRAM1 避免总线竞争 */
static dma_ring_buf_t uart2_buf __attribute__((aligned(4)));

/* === 初始化 === */
void ring_buf_init(dma_ring_buf_t *rb) {
    rb->head = 0;
    rb->tail = 0;
}

/* === 数据消费接口 === */
uint16_t ring_buf_available(const dma_ring_buf_t *rb) {
    return rb->head - rb->tail;     /* 可用字节数 */
}

int ring_buf_read(dma_ring_buf_t *rb,
                  uint8_t *out, uint16_t max_len) {
    uint16_t avail = ring_buf_available(rb);
    if (avail == 0) return -1;      /* 空缓冲区 */
    uint16_t len = (max_len < avail) ? max_len : avail;
    for (uint16_t i = 0; i < len; i++) {
        out[i] = rb->buf[rb->tail & (BUFFER_SIZE - 1)];
        rb->tail++;                 /* 推进 tail */
    }
    return (int)len;
}

/* dma_uart_rx.c — UART2 DMA 循环接收 */
#include "stm32f4xx_hal.h"
#include "dma_ring_buf.h"

#define BUFFER_SIZE  256

static UART_HandleTypeDef huart2;
static DMA_HandleTypeDef hdma_usart2_rx;
static dma_ring_buf_t uart2_rx_buf;
static volatile uint8_t dma_flag = 0;  /* 数据就绪标志 */

/* DMA 初始化：Channel5, Peripheral_to_Memory, Circular */
static void dma_rx_init(void) {
    __HAL_RCC_DMA2_CLK_ENABLE();
    hdma_usart2_rx.Instance             = DMA2_Stream5;
    hdma_usart2_rx.Init.Channel         = DMA_CHANNEL_4;
    hdma_usart2_rx.Init.Direction       = DMA_PERIPH_TO_MEMORY;
    hdma_usart2_rx.Init.PeriphInc       = DMA_PINC_DISABLE;
    hdma_usart2_rx.Init.MemInc          = DMA_MINC_ENABLE;
    hdma_usart2_rx.Init.PeriphDataAlignment = DMA_PDATAALIGN_BYTE;
    hdma_usart2_rx.Init.MemDataAlignment  = DMA_MDATAALIGN_BYTE;
    hdma_usart2_rx.Init.Mode            = DMA_CIRCULAR;
    hdma_usart2_rx.Init.Priority        = DMA_PRIORITY_HIGH;
    HAL_DMA_Init(&hdma_usart2_rx);
    __HAL_LINKDMA(&huart2, hdmarx, hdma_usart2_rx);
    NVIC_SetPriority(DMA2_Stream5_IRQn, 3);
    HAL_NVIC_EnableIRQ(DMA2_Stream5_IRQn);
}

/* UART2 初始化并启动 DMA 循环接收 */
void uart2_dma_begin(void) {
    __HAL_RCC_USART2_CLK_ENABLE();
    __HAL_RCC_GPIOA_CLK_ENABLE();
    /* PA2=TX, PA3=RX */
    GPIO_InitTypeDef gi = {0};
    gi.Pin   = GPIO_PIN_2 | GPIO_PIN_3;
    gi.Mode  = GPIO_MODE_AF_PP;
    gi.Pull  = GPIO_PULLUP;
    gi.Speed = GPIO_SPEED_FREQ_HIGH;
    gi.Alternate = GPIO_AF7_USART2;
    HAL_GPIO_Init(GPIOA, &gi);

    huart2.Instance          = USART2;
    huart2.Init.BaudRate     = 115200;
    huart2.Init.WordLength   = UART_WORDLENGTH_8B;
    huart2.Init.StopBits     = UART_STOPBITS_1;
    huart2.Init.Parity       = UART_PARITY_NONE;
    huart2.Init.Mode         = UART_MODE_TX_RX;
    HAL_UART_Init(&huart2);

    dma_rx_init();
    ring_buf_init(&uart2_rx_buf);

    /* 启动 DMA 循环接收：数据写入 ring_buf.buf */
    HAL_UART_Receive_DMA(&huart2,
        (uint8_t*)uart2_rx_buf.buf,
        BUFFER_SIZE);
}

/* DMA 传输完成回调：仅设标志，不做耗时操作 */
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    if (huart->Instance == USART2)
        dma_flag = 1;  /* 告诉主循环有数据 */
}

/* 主循环消费示例 */
int main(void) {
    HAL_Init();
    uart2_dma_begin();
    uint8_t tmp[64];
    while (1) {
        if (dma_flag) {
            dma_flag = 0;
            uint16_t avail = ring_buf_available(
                &uart2_rx_buf);
            if (avail > 0) {
                int n = ring_buf_read(
                    &uart2_rx_buf, tmp,
                    (avail < 64) ? avail : 64);
                /* 处理 n 字节数据 */
            }
        }
    }
}

/* 陷阱五演示：uint16_t 回绕问题 */

/* ❌ 错误做法 */
typedef struct {
    uint8_t  buf[256];
    uint16_t head;              /* 16-bit 会回绕！ */
    uint16_t tail;              /* 16-bit 会回绕！ */
} bad_ring_buf_t;

uint16_t bad_available(const bad_ring_buf_t *rb) {
    /* 当 head=0, tail=65535 时：0 - 65535 = 1 (错误!) */
    return rb->head - rb->tail;
}

/* ✅ 正确做法：uint32_t 天然处理回绕 */
typedef struct {
    uint8_t  buf[256];
    volatile uint32_t head;     /* 32-bit 不易回绕 */
    volatile uint32_t tail;     /* 32-bit 不易回绕 */
} good_ring_buf_t;

uint32_t good_available(const good_ring_buf_t *rb) {
    return rb->head - rb->tail; /* 减法天然处理回绕 */
}

