int main(void) {
    HAL_Init();
    uart_init();
    uint8_t single_byte;
    uint8_t packet[128];
    uint16_t pkt_idx = 0;
    while (1) {
        /* 逐字节轮询接收 —— CPU 被完全占用 */
        HAL_UART_Receive(&huart2, &single_byte, 1, 10);
        packet[pkt_idx++] = single_byte;  /* 手动拷贝 */
        if (pkt_idx >= 128 || single_byte == 0xFF) {
            process_data(packet, pkt_idx);  /* 耦合严重 */
            pkt_idx = 0;
        }
    }
}

/* ===== 重构后：DMA 循环 + 环形缓冲区 ===== */

/* step 1: 环形缓冲区接口 */
uint16_t ring_buf_available(const dma_ring_buf_t *rb);
int      ring_buf_read(dma_ring_buf_t *rb, uint8_t *out,
                       uint16_t max_len);

/* step 2: DMA 在 uart2_dma_begin() 中自动填充缓冲区 */
/* step 3: 主循环只关心消费 */
int main(void) {
    HAL_Init();
    uart2_dma_begin();               /* DMA 循环接收已启动 */
    uint8_t packet[128];
    while (1) {
        uint16_t avail = ring_buf_available(&uart2_rx_buf);
        if (avail > 0) {
            uint16_t len = (avail < 128) ? avail : 128;
            ring_buf_read(&uart2_rx_buf, packet, len);
            process_data(packet, len); /* 纯业务逻辑 */
        }
        /* CPU 空闲时可做其他事 */
        low_power_idle();
    }
}
